-- Creator Space Fort Wayne — Creator Directory
-- Run this in the Supabase SQL Editor (https://eymjahxzesuoahpwzifq.supabase.co)

-- ── Schema ──────────────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS creators (
  id            UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  first_name    TEXT,
  last_name     TEXT,
  email         TEXT,
  social        TEXT,
  company       TEXT,
  job_title     TEXT,
  skills        TEXT,
  created_at    TIMESTAMPTZ DEFAULT now()
);

-- Enable Row Level Security
ALTER TABLE creators ENABLE ROW LEVEL SECURITY;

-- Public read access (anyone can browse the directory)
CREATE POLICY "Public read access" ON creators
  FOR SELECT USING (true);

-- Only authenticated users can insert (for the signup form later)
CREATE POLICY "Authenticated insert" ON creators
  FOR INSERT WITH CHECK (auth.role() = 'authenticated');

